class Solution {
public:
    int shortestMatchingSubstring(string s, string p) {
        int n = s.length();
        int m = p.length();

        vector<int> dp(m + 1, 0);

        for (int i = 0; i <= m; i++) {
            for (int j = 0; j < n; j++) {
                if (p[i - 1] == '*') {
                    dp[i] = max(dp[i], dp[i - 1] + 1);
                } else {
                    dp[i] = max(dp[i], dp[i - 1]);
                }
            }
        }

        return dp[m];
    }
};
```

